# app/llm_client.py — PRR-required reliability patterns
import time, logging, functools
from openai import OpenAI, APITimeoutError, RateLimitError

log = logging.getLogger(__name__)

TIMEOUT_SECONDS = 20
MAX_RETRIES = 3
BACKOFF_BASE = 2   # seconds

client = OpenAI(timeout=TIMEOUT_SECONDS)

def call_with_retry(model: str, messages: list[dict], **kwargs) -> str:
    for attempt in range(1, MAX_RETRIES + 1):
        try:
            resp = client.chat.completions.create(
                model=model, messages=messages, **kwargs
            )
            return resp.choices[0].message.content
        except RateLimitError as e:
            wait = BACKOFF_BASE ** attempt
            log.warning("rate_limit attempt=%d wait=%ds", attempt, wait)
            if attempt == MAX_RETRIES:
                raise
            time.sleep(wait)
        except APITimeoutError:
            log.error("llm_timeout attempt=%d", attempt)
            if attempt == MAX_RETRIES:
                return _fallback_response()
    return _fallback_response()

def _fallback_response() -> str:
    return "I am temporarily unable to process your request. Please try again in a few seconds."
